mapper.select:

select t.*,
       w.id as w_id, w.code as warehouse_code, w.name as warehouse_name
from purchase_forecast_task t
left join fd_warehouse w on w.id = t.warehouse_id
where (t.del_flag is null or t.del_flag = '0')
  and t.tenant_id = #{scopedTenantId}
and t.warehouse_id = #{warehouseId}
and t.task_no like concat('%', #{taskNo}, '%')
and t.status = #{status}
and t.is_gz = #{isGz}
and date(t.create_time) >= #{beginDate}
and date(t.create_time) <= #{endDate}
order by t.id desc

mapper.insert:
insert into purchase_forecast_task (
  task_no, warehouse_id, is_gz, calc_days, lead_time_days, safety_days,
  status, generated_plan_ids, generated_plan_nos, tenant_id, del_flag,
  create_by, create_time, remark
) values (
  #{taskNo}, #{warehouseId}, #{isGz}, #{calcDays}, #{leadTimeDays}, #{safetyDays},
  #{status}, #{generatedPlanIds}, #{generatedPlanNos}, #{tenantId}, '0',
  #{createBy}, #{createTime}, #{remark}
)

mapper.update:
update purchase_forecast_task
status = #{status}, generated_plan_ids = #{generatedPlanIds}, generated_plan_nos = #{generatedPlanNos}, remark = #{remark}, update_by = #{updateBy}, update_time = #{updateTime}
where id = #{id}

update purchase_forecast_entry

  confirm_qty = #{confirmQty},
  selected = #{selected},
  update_by = #{updateBy},
  update_time = #{updateTime}

where id = #{id}

mapper.select:

select max(task_no) from purchase_forecast_task
where tenant_id = #{scopedTenantId}
  and task_no like concat('YCB', #{dateNum}, '%')

select fn.material_id as materialId, fn.warehouse_id as warehouseId, fn.lower_limit as lowerLimit, fn.upper_limit as upperLimit, m.supplier_id as supplierId, m.price as price, m.min_package_qty as minPackageQty, m.code as materialCode, m.name as materialName, m.speci as speci, m.model as model, m.is_gz as isGz, u.unit_name as unitName, s.name as supplierName from wh_fixed_number fn inner join fd_material m on m.id = fn.material_id and (m.del_flag is null or m.del_flag = 0 or m.del_flag = '0') and (m.is_use is null or m.is_use = '1' or m.is_use = 1) left join fd_unit u on u.unit_id = m.unit_id left join fd_supplier s on s.id = m.supplier_id where (fn.del_flag is null or fn.del_flag = 0) and fn.enable_status = '0' and fn.monitoring = '1' and fn.warehouse_id = #{warehouseId} and (fn.tenant_id = #{scopedTenantId} or fn.tenant_id is null)
and m.is_gz = #{isGz}
order by m.code

select b.material_id as materialId, coalesce(sum( case when stk.bill_type = 201 then ifnull(b.qty, 0) when stk.bill_type = 401 then -ifnull(b.qty, 0) else 0 end ), 0) as qty from stk_io_bill stk inner join stk_io_bill_entry b on b.paren_id = stk.id and (b.del_flag is null or b.del_flag != 1) where (stk.del_flag is null or stk.del_flag != 1) and stk.tenant_id = #{scopedTenantId} and stk.bill_status = 2 and stk.bill_type in (201, 401) and stk.warehouse_id = #{warehouseId} and stk.bill_date >= #{beginDate} and stk.bill_date < date_add(#{endDate}, interval 1 day) and b.material_id is not null
and b.material_id in #{mid}
group by b.material_id

select e.material_id as materialId, coalesce(sum(ifnull(e.qty, 0)), 0) as qty from purchase_plan p inner join purchase_plan_entry e on e.parent_id = p.id and (e.del_flag is null or e.del_flag = '0') where (p.del_flag is null or p.del_flag = '0') and p.tenant_id = #{scopedTenantId} and p.plan_status in ('0', '1') and p.warehouse_id = #{warehouseId} and e.material_id is not null
and e.material_id in #{mid}
group by e.material_id
